];

const HeroSlider: React.FC = () => {
  const [current, setCurrent] = useState(0);

  useEffect(() => {
    const timer = setInterval(() => {
      setCurrent((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
    }, 6000);
    return () => clearInterval(timer);
  }, []);

  const next = () => setCurrent((prev) => (prev === slides.length - 1 ? 0 : prev + 1));
  const prev = () => setCurrent((prev) => (prev === 0 ? slides.length - 1 : prev - 1));

  return (
    <section className="relative h-[500px] md:h-[650px] w-full overflow-hidden bg-gray-900">
      {slides.map((slide, index) => (
        <div
          key={index}
          className={`absolute inset-0 transition-opacity duration-1000 ease-in-out ${
            index === current ? 'opacity-100 z-10' : 'opacity-0 z-0'
          }`}
        >
          <img
            src={slide.image}
            alt={slide.title}
            className="w-full h-full object-cover"
          />
          <div className={`absolute inset-0 ${slide.color} flex items-center`}>
            <div className="container mx-auto px-4 md:px-12 text-white">
              <div className={`max-w-2xl transform transition-transform duration-700 ${index === current ? 'translate-y-0 opacity-100' : 'translate-y-10 opacity-0'}`}>
                <h1 className="text-4xl md:text-6xl font-black mb-6 leading-tight">
                  {slide.title}
                </h1>
                <p className="text-xl md:text-2xl mb-10 text-gray-100 font-light leading-relaxed">
                  {slide.description}
                </p>
                <button className="px-10 py-4 bg-white text-blue-900 rounded-full font-black text-lg hover:bg-blue-50 transition-all shadow-xl hover:scale-105 active:scale-95">
                  {slide.cta}
                </button>
              </div>
            </div>
          </div>
        </div>
      ))}

      {/* Controls */}
      <div className="absolute bottom-10 left-10 right-10 flex justify-between items-center z-20 pointer-events-none">
        <div className="flex gap-2 pointer-events-auto">
          {slides.map((_, idx) => (
            <button
              key={idx}
              onClick={() => setCurrent(idx)}
              className={`h-2 rounded-full transition-all ${idx === current ? 'w-12 bg-white' : 'w-2 bg-white/40'}`}
            />
          ))}
        </div>
        <div className="flex gap-4 pointer-events-auto">
          <button onClick={prev} className="p-3 rounded-full bg-black/20 hover:bg-black/40 text-white backdrop-blur-md transition-all">
            <ChevronRight className="w-6 h-6" />
          </button>
          <button onClick={next} className="p-3 rounded-full bg-black/20 hover:bg-black/40 text-white backdrop-blur-md transition-all">
            <ChevronLeft className="w-6 h-6" />
          </button>
        </div>
      </div>
    </section>
  );
};

export default HeroSlider;

