import React from 'react';
import { Tag, Share2 } from 'lucide-react';

const Discounts: React.FC = () => {
  const offers = [
    { title: 'علاجات الأسنان', discount: '50%', image: 'https://picsum.photos/id/1027/400/300' },
    { title: 'الجلدية والليزر', discount: '30%', image: 'https://picsum.photos/id/111/400/300' },
    { title: 'الفحص الشامل', discount: '40%', image: 'https://picsum.photos/id/146/400/300' },
    { title: 'النظارات الطبية', discount: '25%', image: 'https://picsum.photos/id/160/400/300' },
  ];

  const handleShare = (e: React.MouseEvent, title: string, discount: string) => {
    e.stopPropagation();
    e.preventDefault();

    const shareData = {
      title: `عرض أمان إيفر: ${title}`,
      text: `احصل على خصم ${discount} على ${title} مع تطبيق أمان إيفر!`,
      url: window.location.href,
    };

    if (navigator.share) {
      navigator.share(shareData).catch((err) => {
        console.error('Error sharing:', err);
      });
    } else {
      // Fallback: Copy to clipboard
      navigator.clipboard.writeText(`${shareData.text} ${shareData.url}`)
        .then(() => alert('تم نسخ رابط العرض لمشاركته!'))
        .catch(() => alert('عذراً، لا يمكن مشاركة هذا العرض في متصفحك حالياً.'));
    }
  };

  return (
    <section className="py-20 bg-white">
      <div className="container mx-auto px-4">
        <div className="flex justify-between items-end mb-12">
          <div>
            <h2 className="text-3xl md:text-4xl font-black text-blue-900 mb-4">أقوى الخصومات الحصرية</h2>
            <p className="text-gray-500 font-bold">عروض مميزة وحصرية لمشتركي أمان إيفر فقط</p>
          </div>
          <button className="hidden md:block px-6 py-2 border-b-2 border-blue-600 text-blue-600 font-black hover:text-blue-800 transition-colors">مشاهدة الكل</button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8">
          {offers.map((offer, idx) => (
            <div key={idx} className="relative group overflow-hidden rounded-[2rem] shadow-lg bg-gray-900">
              <img 
                src={offer.image} 
                alt={offer.title} 
                className="w-full h-72 object-cover opacity-80 group-hover:scale-110 transition-transform duration-700 ease-out"
              />

              {/* Share Button */}
              <button 
                onClick={(e) => handleShare(e, offer.title, offer.discount)}
                className="absolute top-4 left-4 z-20 p-3 rounded-full bg-white/10 hover:bg-white/30 text-white backdrop-blur-md border border-white/20 transition-all opacity-0 group-hover:opacity-100 hover:scale-110 active:scale-90"
                title="مشاركة العرض"
              >
                <Share2 size={18} />
              </button>

              <div className="absolute inset-0 bg-gradient-to-t from-black/90 via-black/20 to-transparent p-6 flex flex-col justify-end">
                <div className="flex items-center gap-2 mb-2">
                  <span className="bg-red-600 text-white px-3 py-1 rounded-full text-xs font-black flex items-center gap-1 shadow-lg">
                    <Tag size={12} /> خصم {offer.discount}
                  </span>
                </div>
                <h3 className="text-2xl font-black text-white">{offer.title}</h3>
                <p className="text-gray-300 text-sm mt-2 opacity-0 group-hover:opacity-100 transition-all duration-500 translate-y-4 group-hover:translate-y-0">
                  احصل على العرض الآن عبر التطبيق
