import React, { useState } from 'react';
import { MapPin, Navigation, Hospital, Loader2, AlertCircle } from 'lucide-react';
import { ToastType } from './Toast';

interface NearbyServicesProps {
  notify?: (message: string, type: ToastType) => void;
}

const NearbyServices: React.FC<NearbyServicesProps> = ({ notify }) => {
  const [loading, setLoading] = useState(false);
  const [location, setLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleGetLocation = () => {
    setLoading(true);
    setError(null);

    if (!navigator.geolocation) {
      const msg = 'عذراً، متصفحك لا يدعم تحديد الموقع الجغرافي.';
      setError(msg);
      notify?.(msg, 'error');
      setLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (position) => {
        setLocation({
          lat: position.coords.latitude,
          lng: position.coords.longitude,
        });
        setLoading(false);
        notify?.('تم تحديد موقعك بنجاح!', 'success');
      },
      (err) => {
        let errorMsg = 'حدث خطأ أثناء محاولة تحديد موقعك.';

        switch (err.code) {
          case err.PERMISSION_DENIED:
            errorMsg = 'تم رفض الإذن لتحديد الموقع. يرجى تفعيل الموقع من إعدادات المتصفح.';
            break;
          case err.POSITION_UNAVAILABLE:
            errorMsg = 'معلومات الموقع غير متوفرة حالياً.';
            break;
          case err.TIMEOUT:
            errorMsg = 'انتهت مهلة طلب تحديد الموقع.';
            break;
        }

        setError(errorMsg);
        notify?.(errorMsg, 'error');
        setLoading(false);
      },
      { timeout: 10000 }
    );
  };

  return (
    <section className="py-20 bg-blue-900 text-white overflow-hidden relative">
      <div className="container mx-auto px-4 relative z-10">
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-12 items-center">
          <div>
            <h2 className="text-4xl md:text-5xl font-black mb-8 leading-tight">خدمات بالقرب منك</h2>
            <p className="text-xl text-blue-100 mb-10 font-bold leading-relaxed max-w-lg">
              ابحث عن أقرب مقدم خدمة طبية لموقعك الحالي. نظامنا الذكي يحدد لك الأقرب والأفضل تقييماً في ثوانٍ.
            </p>

            <div className="flex flex-col sm:flex-row gap-4">
              <button 
                onClick={handleGetLocation}
                disabled={loading}
                className="px-8 py-4 bg-white text-blue-900 rounded-full font-black flex items-center justify-center gap-3 hover:bg-blue-50 transition-all disabled:opacity-70 disabled:cursor-not-allowed group"
              >
                {loading ? (
                  <Loader2 className="w-5 h-5 animate-spin" />
                ) : (
                  <Navigation className="w-5 h-5 group-hover:animate-pulse" />
                )}
                {loading ? 'جاري التحديد...' : 'تحديد موقعي الآن'}
              </button>
              <button className="px-8 py-4 bg-blue-800 text-white border border-blue-700 rounded-full font-black flex items-center justify-center gap-3 hover:bg-blue-700 transition-all">
                استعراض الخريطة
              </button>
            </div>

            {error && (
              <div className="mt-6 flex items-center gap-2 text-red-300 bg-red-900/30 p-4 rounded-2xl border border-red-800/50 animate-in fade-in slide-in-from-top-2 duration-300">
                <AlertCircle size={20} className="shrink-0" />
                <span className="text-sm font-bold">{error}</span>
              </div>
            )}
          </div>

          <div className="relative">
            <div className="w-full aspect-video md:aspect-square bg-gray-200 rounded-[3rem] overflow-hidden shadow-2xl border-8 border-blue-800/50">
              <div className={`absolute inset-0 bg-cover opacity-50 transition-all duration-1000 ${location ? 'grayscale-0 scale-105' : 'grayscale'}`} style={{ backgroundImage: "url('https://images.unsplash.com/photo-1526778548025-fa2f459cd5c1?auto=format&fit=crop&q=80&w=800')" }}></div>

              {/* Conditional Location Pins */}
              {location && (
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 z-20">
                   <div className="relative">
                      <div className="absolute -inset-4 bg-blue-500 rounded-full animate-ping opacity-25"></div>
                      <div className="relative w-6 h-6 bg-blue-600 rounded-full border-4 border-white shadow-xl"></div>
                   </div>
                </div>
              )}

              <div className="absolute top-1/4 right-1/3 text-blue-600 animate-bounce">
                <MapPin size={48} fill="currentColor" className="text-white" />
              </div>
              <div className="absolute bottom-1/3 left-1/4 text-emerald-600">
                <MapPin size={32} fill="currentColor" className="text-white" />
              </div>

              <div className="absolute bottom-6 left-6 right-6 bg-white p-4 rounded-2xl text-gray-800 shadow-xl flex items-center gap-4 group hover:scale-[1.02] transition-transform cursor-pointer">
                <div className="w-12 h-12 bg-blue-100 rounded-lg flex items-center justify-center text-blue-600 group-hover:bg-blue-600 group-hover:text-white transition-colors">
